import { Mesh } from 'three';

import {
  ContactShadows,
  OrbitControls,
  PerspectiveCamera,
  RenderTexture,
  Text,
} from '@react-three/drei';
import { Canvas, GroupProps, useFrame } from '@react-three/fiber';
import * as React from 'react';

export type Props = {};

function App(props: Props) {
  const {} = props;
  return (
    <Canvas
      style={{ height: '50vh' }}
      camera={{ position: [5, 5, 5], fov: 25 }}
    >
      <ambientLight intensity={0.5} />
      <directionalLight position={[10, 10, 5]} />
      <Cube />
      <Dodecahedron position={[0, 1, 0]} scale={0.2} />
      <ContactShadows
        frames={1}
        position={[0, -0.5, 0]}
        blur={1}
        opacity={0.7}
      />
      <ContactShadows
        frames={1}
        position={[0, -0.5, 0]}
        blur={3}
        color="orange"
      />
      <OrbitControls minPolarAngle={0} maxPolarAngle={Math.PI / 2.1} />
    </Canvas>
  );
}

export default React.memo(App);

// console.log({ inter });
function Cube() {
  const [font, setFont] = React.useState('');
  React.useEffect(() => {
    import('@pmndrs/assets/fonts/inter_regular.woff').then((module) =>
      setFont(module.default)
    );
  }, []);
  const textRef = React.useRef<Mesh>();
  useFrame(({ clock }) => {
    if (textRef.current) {
      textRef.current.position.x = Math.sin(clock.elapsedTime) * 2;
    }
  });
  return (
    <mesh>
      <boxGeometry />
      <meshStandardMaterial>
        <RenderTexture attach="map" anisotropy={16}>
          <PerspectiveCamera
            makeDefault
            manual
            aspect={1 / 1}
            position={[0, 0, 5]}
          />
          <color attach="background" args={['orange']} />
          <ambientLight intensity={0.5} />
          <directionalLight position={[10, 10, 5]} />
          <Text font={font} ref={textRef} fontSize={4} color="#555">
            hello
          </Text>
          <Dodecahedron />
        </RenderTexture>
      </meshStandardMaterial>
    </mesh>
  );
}

function Dodecahedron(props: GroupProps) {
  const refMesh = React.useRef<Mesh>(null!);
  const [hovered, setHovered] = React.useState(false);
  const [clicked, setClicked] = React.useState(false);
  useFrame(() => (refMesh.current.rotation.x += 0.01));
  return (
    <group {...props}>
      <mesh
        ref={refMesh}
        scale={clicked ? 1.5 : 1}
        onClick={() => setClicked((v) => !v)}
        onPointerOver={() => setHovered(true)}
        onPointerOut={() => setHovered(false)}
      >
        <dodecahedronGeometry args={[0.75]} />
        <meshStandardMaterial color={hovered ? 'hotpink' : '#5de4c7'} />
      </mesh>
    </group>
  );
}
